import boto3, json, time

bedrock = boto3.client("bedrock", region_name="us-east-1")

# Input JSONL must already be in S3
job = bedrock.create_model_invocation_job(
    jobName="sentiment-batch-2024-01-15",
    modelId="anthropic.claude-opus-4-8",
    inputDataConfig={
        "s3InputDataConfig": {
            "s3Uri": "s3://my-bucket/input/requests.jsonl",
        }
    },
    outputDataConfig={
        "s3OutputDataConfig": {
            "s3Uri": "s3://my-bucket/output/",
        }
    },
    roleArn="arn:aws:iam::123456789012:role/bedrock-batch-role",
)

job_arn = job["jobArn"]
print(f"Job ARN: {job_arn}")

# Poll until complete (in production, use EventBridge instead of polling)
while True:
    status = bedrock.get_model_invocation_job(jobIdentifier=job_arn)
    state = status["status"]
    print(f"Status: {state}")
    if state in ("Completed", "Failed", "Stopped"):
        break
    time.sleep(60)

import json, boto3

bedrock = boto3.client("bedrock-runtime", region_name="us-east-1")

def lambda_handler(event, context):
    user_message = event.get("message", "")
    body = {
        "anthropic_version": "bedrock-2023-05-31",
        "max_tokens": 512,
        "messages": [{"role": "user", "content": user_message}],
    }
    response = bedrock.invoke_model(
        modelId="anthropic.claude-opus-4-8",
        body=json.dumps(body),
    )
    result = json.loads(response["body"].read())
    return {"statusCode": 200, "body": result["content"][0]["text"]}

import boto3

bedrock_agent = boto3.client("bedrock-agent-runtime", region_name="us-east-1")

response = bedrock_agent.retrieve_and_generate(
    input={"text": "What is the refund policy?"},
    retrieveAndGenerateConfiguration={
        "type": "KNOWLEDGE_BASE",
        "knowledgeBaseConfiguration": {
            "knowledgeBaseId": "KB12345678",
            "modelArn": "arn:aws:bedrock:us-east-1::foundation-model/anthropic.claude-opus-4-8",
        },
    },
)
print(response["output"]["text"])
